@media screen and (max-width: 749px) {

.product-info {
  padding: 0 18px !important;
}

.product-layout {
  gap: 0 !important;
}

.product-main-image {
  border-bottom: 1px solid #eee !important;
}

.product-persuasion-stack {
  display: grid !important;
  grid-template-columns: 1fr !important;
  gap: 0 !important;
  margin: 14px 0 10px !important;
  padding: 0 !important;
  border-top: 1px solid #e8e3d8 !important;
  border-bottom: 1px solid #e8e3d8 !important;
}

.persuasion-row {
  padding: 11px 0 !important;
  border-bottom: 1px solid #f0ece3 !important;
  font-size: 13px !important;
  line-height: 1.45 !important;
  display: flex !important;
  gap: 8px !important;
  align-items: baseline !important;
}

.persuasion-row:last-child {
  border-bottom: none !important;
}

#product-price-main {
  font-size: 30px !important;
  font-weight: 800 !important;
  color: #111 !important;
  letter-spacing: -0.03em !important;
  line-height: 1.1 !important;
}

.product-price-wrap {
  display: flex !important;
  align-items: baseline !important;
  gap: 10px !important;
  flex-wrap: wrap !important;
  margin: 6px 0 2px !important;
  padding-bottom: 6px !important;
  border-bottom: 1px solid #f0f0f0 !important;
}

.product-review-callout {
  margin: 12px 0 !important;
  padding: 14px 16px !important;
  background: transparent !important;
  border: none !important;
  border-left: 3px solid #111 !important;
  font-size: 13.5px !important;
  line-height: 1.55 !important;
  color: #444 !important;
}

.product-thumbnails {
  display: flex !important;
  gap: 6px !important;
  padding: 6px 0 10px !important;
  justify-content: flex-start !important;
  overflow-x: auto !important;
  -webkit-overflow-scrolling: touch !important;
  scrollbar-width: none !important;
}

.product-thumbnails::-webkit-scrollbar {
  display: none !important;
}

.product-thumbnails button {
  flex: 0 0 54px !important;
  height: 54px !important;
  border-radius: 6px !important;
  border: 2px solid #e5e5e5 !important;
  overflow: hidden !important;
  padding: 0 !important;
  background: #fff !important;
}

.product-thumbnails button.active,
.product-thumbnails button[aria-current="true"] {
  border-color: #111 !important;
}

.sealsubs-target-element {
  margin: 12px 0 !important;
}

.sls-purchase-options-container {
  display: grid !important;
  grid-template-columns: 1fr 1fr !important;
  gap: 8px !important;
}

.sls-option-container {
  border: 2px solid #e0e0e0 !important;
  border-radius: 8px !important;
  padding: 12px 10px !important;
  margin-bottom: 0 !important;
  text-align: center !important;
  font-size: 12.5px !important;
  line-height: 1.4 !important;
  transition: border-color 0.15s ease !important;
}

.sls-option-container.sls-active {
  border-color: #111 !important;
  background: #fafafa !important;
  box-shadow: inset 0 0 0 1px #111 !important;
}

.sls-more-info-container {
  margin-top: 4px !important;
  font-size: 12px !important;
}

.product-actions {
  position: sticky !important;
  bottom: 0 !important;
  z-index: 90 !important;
  background: #fff !important;
  padding: 10px 18px max(10px, env(safe-area-inset-bottom)) !important;
  margin: 0 -18px !important;
  box-shadow: 0 -1px 0 #e5e5e5, 0 -8px 24px rgba(0,0,0,0.06) !important;
}

.product-actions button[type="submit"],
.product-actions .add-to-cart,
.product-actions [class*="add-to-cart"] {
  background: #111 !important;
  color: #fff !important;
  font-size: 15px !important;
  font-weight: 700 !important;
  padding: 16px 24px !important;
  border-radius: 50px !important;
  width: 100% !important;
  min-height: 52px !important;
  border: none !important;
  cursor: pointer !important;
  letter-spacing: 0.01em !important;
}

.product-quantity {
  display: flex !important;
  align-items: center !important;
  gap: 6px !important;
  margin-bottom: 8px !important;
  justify-content: center !important;
}

.quantity-selector {
  border: 1.5px solid #ddd !important;
  border-radius: 50px !important;
  overflow: hidden !important;
  display: inline-flex !important;
}

.quantity-selector button {
  min-width: 40px !important;
  min-height: 40px !important;
  border: none !important;
  background: transparent !important;
  font-size: 16px !important;
}

.guarantee-badge {
  text-align: center !important;
  padding: 10px 14px !important;
  margin: 8px 0 0 !important;
  font-size: 12.5px !important;
  font-weight: 600 !important;
  color: #555 !important;
  letter-spacing: 0.02em !important;
  border: 1px dashed #ccc !important;
  border-radius: 6px !important;
  background: transparent !important;
}

.product-story {
  margin: 32px -18px !important;
  padding: 32px 24px 28px !important;
  background: #f5f2eb !important;
  text-align: center !important;
  border-top: 3px solid #111 !important;
}

.story-content {
  font-size: 15px !important;
  line-height: 1.65 !important;
  color: #333 !important;
  max-width: 340px !important;
  margin: 0 auto !important;
}

.story-content h2,
.story-content h3,
.product-story h2,
.product-story h3 {
  font-size: 18px !important;
  font-weight: 800 !important;
  color: #111 !important;
  letter-spacing: -0.02em !important;
  margin-bottom: 8px !important;
  text-transform: none !important;
}

.story-stats {
  display: grid !important;
  grid-template-columns: repeat(3, 1fr) !important;
  gap: 0 !important;
  margin-top: 24px !important;
  border-top: 1px solid #ddd8cc !important;
  padding-top: 20px !important;
}

.stat {
  text-align: center !important;
  padding: 0 8px !important;
  border-right: 1px solid #ddd8cc !important;
  font-size: 9.5px !important;
  font-weight: 700 !important;
  text-transform: uppercase !important;
  letter-spacing: 0.08em !important;
  color: #666 !important;
  line-height: 1.3 !important;
}

.stat:last-child {
  border-right: none !important;
}

.stat strong,
.stat b,
.stat .stat-number {
  display: block !important;
  font-size: 26px !important;
  font-weight: 800 !important;
  color: #111 !important;
  letter-spacing: -0.02em !important;
  margin-bottom: 4px !important;
}

#product-reviews,
.hg-reviews-ready {
  padding: 28px 0 16px !important;
  margin-top: 0 !important;
}

.jdgm-rev-widg__header {
